// Parse PEDIDO_LISTO signal from Groq
const full = $('Groq IA - Ventas').item.json.choices[0].message.content;
const lines = full.split('\n');
const signal = lines[0]; // PEDIDO_LISTO|producto=...|precio=...|nombre=...|direccion=...|telefono=...
const msgLines = lines.slice(1).join('\n').trim();

// Parse key=value pairs
const parts = {};
signal.split('|').slice(1).forEach(p => {
  const idx = p.indexOf('=');
  if (idx > -1) parts[p.substring(0,idx)] = p.substring(idx+1);
});

const producto = parts.producto || 'Producto MSN Products';
const precio = parseInt(parts.precio) || 80000;
const nombre = parts.nombre || 'Cliente';
const direccion = parts.direccion || '';
const telefono = parts.telefono || '';
const wa_id = $('Webhook POST').item.json.body.entry[0].changes[0].value.contacts[0].wa_id;

return [{ json: { producto, precio, nombre, direccion, telefono, wa_id, confirmMsg: msgLines } }];

const datos = $('Parsear Datos Pedido').item.json;
const pay_link = $('Generar Link Mercado Pago').item.json.init_point;
const confirmMsg = datos.confirmMsg || 'Perfecto! Tu pedido esta listo.';

return [{
  json: {
    messaging_product: 'whatsapp',
    to: datos.wa_id,
    type: 'text',
    text: { body: confirmMsg + '\n\nLink de pago seguro: ' + pay_link + '\n\nGracias por elegir MSN Products! 🛍️' }
  }
}];

const webhook = $('Webhook POST').item.json;
const wa_id = webhook.body.entry[0].changes[0].value.contacts[0].wa_id;
const groqReply = $('Groq IA - Ventas').item.json.choices[0].message.content;
// Remove any PEDIDO_LISTO signal if present
const lines = groqReply.split('\n');
const cleanReply = lines[0].startsWith('PEDIDO_LISTO|') ? lines.slice(1).join('\n').trim() : groqReply;
return [{
  json: {
    messaging_product: 'whatsapp',
    to: wa_id,
    type: 'text',
    text: { body: cleanReply }
  }
}];
